/**
 * Daily QT reading-plan algorithm — ported from the app's
 * src/lib/dailyPlan.ts (+ computus.ts + data/verseCounts.ts +
 * data/christmasReadings.ts) so the worker's cron trigger can
 * independently compute "today's reading" and pre-warm the
 * /qt-reflection cache before anyone opens the app.  Keep this in
 * sync by hand if the app's algorithm ever changes — there's no
 * shared package between the two repos.
 *
 * bookIdx is 0-indexed, matching this file's own BOOK_CHAPTERS /
 * VERSE_COUNTS order — the same standard 66-book Protestant order as
 * index.js's BOOK_NAMES_EN/BOOK_NAMES_KO/BOOK_CHAPTERS.
 */

