function versesInChapter(bookIdx, chapter) {
  return VERSE_COUNTS[bookIdx]?.[chapter - 1] ?? 0;
}

// ===== computus.ts port =====

function easterSunday(year) {
  const a = year % 19;
  const b = Math.floor(year / 100);
  const c = year % 100;
  const d = Math.floor(b / 4);
  const e = b % 4;
  const f = Math.floor((b + 8) / 25);
  const g = Math.floor((b - f + 1) / 3);
  const h = (19 * a + b - d - g + 15) % 30;
  const i = Math.floor(c / 4);
  const k = c % 4;
  const l = (32 + 2 * e + 2 * i - h - k) % 7;
  const m = Math.floor((a + 11 * h + 22 * l) / 451);
  const month = Math.floor((h + l - 7 * m + 114) / 31);
  const day = ((h + l - 7 * m + 114) % 31) + 1;
  return new Date(year, month - 1, day);
}

function palmSunday(year) {
  const easter = easterSunday(year);
  return new Date(easter.getFullYear(), easter.getMonth(), easter.getDate() - 7);
}

function toDayNumber(date) {
  return Math.floor(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()) / 86400000);
}

function isHolyWeek(date) {
  const y = date.getFullYear();
  const d = toDayNumber(date);
  return d >= toDayNumber(palmSunday(y)) && d <= toDayNumber(easterSunday(y));
}

// ===== christmasReadings.ts port =====
// bookIdx values below match this file's own BOOK_CHAPTERS/VERSE_COUNTS
// order: 22=Isaiah, 32=Micah, 41=Luke, 39=Matthew, 42=John, 55=Titus, 18=Psalms.

const CHRISTMAS_READINGS = {
  18: { bookIdx: 22, chapter: 9, verseStart: 2, verseEnd: 7 },
  19: { bookIdx: 22, chapter: 7, verseStart: 10, verseEnd: 14 },
  20: { bookIdx: 32, chapter: 5, verseStart: 2, verseEnd: 5 },
  21: { bookIdx: 41, chapter: 1, verseStart: 26, verseEnd: 38 },
  22: { bookIdx: 41, chapter: 1, verseStart: 46, verseEnd: 56 },
  23: { bookIdx: 39, chapter: 1, verseStart: 18, verseEnd: 25 },
  24: { bookIdx: 41, chapter: 2, verseStart: 1, verseEnd: 7 },
  25: { bookIdx: 41, chapter: 2, verseStart: 8, verseEnd: 20 },
  26: { bookIdx: 39, chapter: 2, verseStart: 1, verseEnd: 12 },
  27: { bookIdx: 42, chapter: 1, verseStart: 1, verseEnd: 14 },
  28: { bookIdx: 41, chapter: 2, verseStart: 21, verseEnd: 40 },
  29: { bookIdx: 55, chapter: 2, verseStart: 11, verseEnd: 14 },
  30: { bookIdx: 55, chapter: 3, verseStart: 4, verseEnd: 7 },
  31: { bookIdx: 18, chapter: 90, verseStart: 1, verseEnd: 12 },
};

// ===== dailyPlan.ts port =====

const MATTHEW = 39, MARK = 40, LUKE = 41, JOHN = 42, PSALMS = 18;

const GOSPEL_ROTATION_BASE_YEAR = 2024;
const GOSPEL_ROTATION = [MARK, JOHN, MATTHEW, LUKE];

function gospelBookIdxForYear(year) {
  const offset = (((year - GOSPEL_ROTATION_BASE_YEAR) % 4) + 4) % 4;
  return GOSPEL_ROTATION[offset];
}

const HOLY_WEEK_CHAPTER_COUNT = { [MATTHEW]: 3, [MARK]: 3, [LUKE]: 3, [JOHN]: 4 };

// Same book order/grouping as the app's MAIN_QUEUE_BLOCKS, expressed
// as this file's own 0-indexed bookIdx values instead of BOOKS.findIndex.
// Genesis=0 Exodus=1 Leviticus=2 Numbers=3 Deuteronomy=4 Joshua=5 Judges=6
// Ruth=7 1Sam=8 2Sam=9 1Ki=10 2Ki=11 1Chr=12 2Chr=13 Ezra=14 Neh=15
// Esther=16 Job=17 Psalms=18 Prov=19 Eccl=20 Song=21 Isaiah=22 Jer=23
// Lam=24 Ezek=25 Dan=26 Hos=27 Joel=28 Amos=29 Obad=30 Jonah=31 Micah=32
// Nahum=33 Hab=34 Zeph=35 Hag=36 Zech=37 Mal=38 Matt=39 Mark=40 Luke=41
// John=42 Acts=43 Rom=44 1Cor=45 2Cor=46 Gal=47 Eph=48 Phil=49 Col=50
// 1Thess=51 2Thess=52 1Tim=53 2Tim=54 Titus=55 Phlm=56 Heb=57 James=58
// 1Pet=59 2Pet=60 1Jn=61 2Jn=62 3Jn=63 Jude=64 Rev=65
const MAIN_QUEUE_BLOCKS = [
  [0], [44, 55], [1], [49, 30, 56], [5, 6, 7], [45, 31], [8, 9], [47, 33],
  [10, 11], [46, 34], [22], [48, 35], [17], [50, 36, 38], [23, 24],
  [51, 52, 32], [3], [53, 54, 27], [25], [57, 28], [12, 13], [58, 29],
  [2], [59, 37], [26], [60, 61, 62, 63, 64], [4], [20, 21], [43],
  [19, 14, 15, 16], [65],
];
const MAIN_QUEUE = MAIN_QUEUE_BLOCKS.flat();

const TARGET_VERSES_PER_DAY_MAIN = 8;
const TARGET_VERSES_PER_DAY_PSALMS = 6;

function splitChapterIntoDays(bookIdx, chapter, dayCount) {
  const total = versesInChapter(bookIdx, chapter);
  const n = Math.max(1, dayCount);
  const base = Math.floor(total / n);
  const rem = total % n;
  const slots = [];
  let v = 1;
  for (let i = 0; i < n; i++) {
    const len = Math.max(1, base + (i < rem ? 1 : 0));
    const verseStart = v;
    const verseEnd = Math.min(v + len - 1, total);
    slots.push({ bookIdx, chapter, verseStart, verseEnd });
    v = verseEnd + 1;
  }
  return slots;
}

function allocateChapterDays(bookIdx, chapter, targetVersesPerDay) {
  const total = versesInChapter(bookIdx, chapter);
  const dayCount = Math.max(1, Math.ceil(total / targetVersesPerDay));
  return splitChapterIntoDays(bookIdx, chapter, dayCount);
}

function stretchToFit(bookIdx, chapters, totalDays) {
  if (chapters.length === 0 || totalDays <= 0) return [];
  const days = Math.max(totalDays, chapters.length);
  const verseCounts = chapters.map((c) => versesInChapter(bookIdx, c));
  const totalVerses = verseCounts.reduce((s, v) => s + v, 0);
  const raw = verseCounts.map((v) => (v / totalVerses) * days);
  const dayCounts = raw.map((r) => Math.max(1, Math.floor(r)));
  let remaining = days - dayCounts.reduce((s, v) => s + v, 0);
  const order = raw
    .map((r, i) => ({ i, frac: r - Math.floor(r) }))
    .sort((a, b) => b.frac - a.frac);
  for (let k = 0; k < order.length && remaining > 0; k++, remaining--) {
    dayCounts[order[k].i]++;
  }
  const slots = [];
  chapters.forEach((chapter, i) => {
    slots.push(...splitChapterIntoDays(bookIdx, chapter, dayCounts[i]));
  });
  return slots;
}

function buildSchedule(bookIndices, targetVersesPerDay) {
  const schedule = [];
  for (const bookIdx of bookIndices) {
    const chapterCount = BOOK_CHAPTERS[bookIdx];
    for (let chapter = 1; chapter <= chapterCount; chapter++) {
      schedule.push(...allocateChapterDays(bookIdx, chapter, targetVersesPerDay));
    }
  }
  return schedule;
}

const MAIN_SCHEDULE = buildSchedule(MAIN_QUEUE, TARGET_VERSES_PER_DAY_MAIN);
const PSALMS_SCHEDULE = buildSchedule([PSALMS], TARGET_VERSES_PER_DAY_PSALMS);

const PLAN_EPOCH = new Date(2024, 0, 1);

function classifyDay(date) {
  const month = date.getMonth();
  const day = date.getDate();
  if (month === 11 && day >= 18) return 'christmas';
  if (isHolyWeek(date)) return 'gospel';
  if (date.getDay() === 0) return 'psalms';
  const easter = easterSunday(date.getFullYear());
  if (toDayNumber(date) <= toDayNumber(easter)) return 'gospel';
  return 'main';
}

function typeIndexForDate(date, type) {
  let count = 0;
  const cursor = new Date(PLAN_EPOCH.getFullYear(), PLAN_EPOCH.getMonth(), PLAN_EPOCH.getDate());
  const targetDayNum = toDayNumber(date);
  while (toDayNumber(cursor) < targetDayNum) {
    if (classifyDay(cursor) === type) count++;
    cursor.setDate(cursor.getDate() + 1);
  }
  return count;
}

function slotToReading(type, slot) {
  return { type, bookIdx: slot.bookIdx, chapter: slot.chapter, verseStart: slot.verseStart, verseEnd: slot.verseEnd };
}

function resolveGospelReading(date) {
  const year = date.getFullYear();
  const bookIdx = gospelBookIdxForYear(year);
  const totalChapters = BOOK_CHAPTERS[bookIdx];
  const holyWeekChapters = HOLY_WEEK_CHAPTER_COUNT[bookIdx];

  if (isHolyWeek(date)) {
    const start = palmSunday(year);
    const chapters = Array.from({ length: holyWeekChapters }, (_, i) => totalChapters - holyWeekChapters + 1 + i);
    const windowDays = toDayNumber(easterSunday(year)) - toDayNumber(start) + 1;
    const slots = stretchToFit(bookIdx, chapters, windowDays);
    const offset = toDayNumber(date) - toDayNumber(start);
    const slot = slots[Math.min(offset, slots.length - 1)];
    return slotToReading('gospel', slot);
  }

  const jan1 = new Date(year, 0, 1);
  const palm = palmSunday(year);
  const chapters = Array.from({ length: totalChapters - holyWeekChapters }, (_, i) => i + 1);
  const windowDays = toDayNumber(palm) - toDayNumber(jan1);
  const slots = stretchToFit(bookIdx, chapters, windowDays);
  const offset = toDayNumber(date) - toDayNumber(jan1);
  const slot = slots[Math.min(offset, slots.length - 1)];
  return slotToReading('gospel', slot);
}

/** Same algorithm as the app's getReadingForDate, returning
 *  { type, bookIdx, chapter, verseStart, verseEnd } (bookIdx 0-indexed —
 *  add 1 for the worker's 1-indexed book-number endpoints). */
export function getReadingForDate(date) {
  const type = classifyDay(date);

  if (type === 'christmas') {
    return slotToReading('christmas', CHRISTMAS_READINGS[date.getDate()]);
  }
  if (type === 'gospel') {
    return resolveGospelReading(date);
  }
  const schedule = type === 'psalms' ? PSALMS_SCHEDULE : MAIN_SCHEDULE;
  const index = typeIndexForDate(date, type) % schedule.length;
  return slotToReading(type, schedule[index]);
}
